_customer_service = CustomerService()


def _billing_entry_fg(preferred: str | None = None) -> str:
    contrast = _contrast_text(C["input"], light=C["text"], dark="#111827")
    if preferred and contrast == C["text"]:
        return preferred
    return contrast


def _billing_card_fg(preferred: str | None = None) -> str:
    contrast = _contrast_text(C["card"], light=C["text"], dark="#111827")
    if preferred and contrast == C["text"]:
        return preferred
    return contrast


def _billing_get_customers() -> dict:
    if use_v5_customers_db():
        return _customer_service.build_legacy_customer_map()
    return get_customers()


def _billing_save_customer(phone: str, name: str, birthday: str = "") -> None:
    if use_v5_customers_db():
        existing = _customer_service.get_customer_by_phone(phone) or {}
        _customer_service.save_customer({
            "phone": phone,
            "name": name,
            "birthday": birthday.strip() or existing.get("birthday", ""),
            "vip": bool(existing.get("vip", 0)),
            "points_balance": int(existing.get("points_balance", 0) or 0),
        })
        return
    add_or_update_customer(phone, name)
    if birthday.strip():
        merged = get_customers()
        existing = merged.get(phone, {})
        merged[phone] = {
            **existing,
            "name": name,
            "phone": phone,
            "birthday": birthday.strip(),
        }
        save_customers(merged)


def _billing_record_visit(phone: str, invoice: str, items: list, total: float, payment: str) -> None:
    if use_v5_customers_db():
        _customer_service.record_visit(phone, invoice, total, payment)
        return
    record_visit(phone, invoice, items, total, payment)


def _billing_redeem_points(phone: str, points: int) -> float:
    if use_v5_customers_db():
        return _customer_service.redeem_points(phone, points)
    return redeem_points(phone, points)


def _auto_save_customer(phone: str, name: str, birthday: str = ""):
    """Silently create/update customer in DB on every bill action."""
    if not phone or not name:
        return
    phone = phone.strip()
    name  = name.strip()
    if phone in ("0000000000", "") or name in ("Guest", ""):
        return
    _billing_save_customer(phone, name, birthday)


