        lp_outer = tk.Frame(paned, bg=C["bg"], width=lp_width)
        lp_outer.pack_propagate(False)
        paned.add(lp_outer, weight=scaled_value(4, 5, 6))

        lp_canvas = tk.Canvas(lp_outer, bg=C["bg"], highlightthickness=0)
        lp_vsb    = ttk.Scrollbar(lp_outer, orient="vertical",
                                   command=lp_canvas.yview)
        lp_canvas.configure(yscrollcommand=lp_vsb.set)
        lp_vsb.pack(side=tk.RIGHT, fill=tk.Y)
        lp_canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        lp = tk.Frame(lp_canvas, bg=C["bg"])
        _lp_win = lp_canvas.create_window((0, 0), window=lp, anchor="nw")

        lp.bind("<Configure>",
                lambda e: lp_canvas.configure(
                    scrollregion=lp_canvas.bbox("all")))
        lp_canvas.bind("<Configure>",
                       lambda e: lp_canvas.itemconfig(_lp_win, width=e.width))

        def _lp_scroll(e):
            lp_canvas.yview_scroll(int(-1 * (e.delta / 120)), "units")

        lp_canvas.bind("<Enter>",
                       lambda e: lp_canvas.bind_all("<MouseWheel>", _lp_scroll))
        lp_canvas.bind("<Leave>",
                       lambda e: lp_canvas.unbind_all("<MouseWheel>"))

        # Workspace intro
        intro = tk.Frame(lp, bg=C["card"], padx=compact_pad, pady=scaled_value(12, 10, 8))
        intro.pack(fill=tk.X, pady=(0, 8))
        tk.Label(intro, text="Billing Workspace",
                 font=section_title_font,
                 bg=C["card"], fg=C["text"]).pack(anchor="w")
        tk.Label(intro,
                 text="Build the bill on the left, review and deliver from the right.",
                 font=section_meta_font,
                 bg=C["card"], fg=C["muted"]).pack(anchor="w", pady=(3, 0))

        # Mode buttons
        mf_outer = tk.Frame(lp, bg=C["card"])
        mf_outer.pack(fill=tk.X, pady=(0, 8))
        mf_head = tk.Frame(mf_outer, bg=C["sidebar"], padx=compact_pad, pady=scaled_value(6, 5, 4))
        mf_head.pack(fill=tk.X)
        tk.Label(mf_head, text="Billing Mode",
                 font=(label_font[0], label_font[1], "bold"),
                 bg=C["sidebar"], fg=C["text"]).pack(side=tk.LEFT)
        tk.Label(mf_head, text="Choose what you are adding",
                 font=section_meta_font,
                 bg=C["sidebar"], fg=C["muted"]).pack(side=tk.RIGHT)
        tk.Frame(mf_outer, bg=C["blue"], height=2).pack(fill=tk.X)
        mf = tk.Frame(mf_outer, bg=C["card"], padx=compact_pad, pady=compact_inner_pad)
        mf.pack(fill=tk.X)
        svc_icon = get_nav_icon("billing")
        prd_icon = get_nav_icon("inventory")
        self.btn_svc = ModernButton(mf, text="Services",
            image=svc_icon, compound="left",
            command=lambda: self.set_mode("services"),
            color=C["teal"], hover_color=C["blue"],
            width=scaled_value(140, 120, 100), height=scaled_value(38, 34, 30), radius=8, font=action_font)
        if show_services:
            self.btn_svc.pack(side=tk.LEFT, fill=tk.X, expand=True, padx=(0, 4 if show_products else 0))
        self.btn_prd = ModernButton(mf, text="Products",
            image=prd_icon, compound="left",
            command=lambda: self.set_mode("products"),
            color=C["sidebar"], hover_color=C["blue"],
            width=scaled_value(140, 120, 100), height=scaled_value(38, 34, 30), radius=8, font=action_font)
        if show_products:
            self.btn_prd.pack(side=tk.LEFT, fill=tk.X, expand=True)

        # Customer section
        cx_outer=tk.Frame(lp,bg=C["card"]); cx_outer.pack(fill=tk.X,pady=4)
        _cxh=tk.Frame(cx_outer,bg=C["sidebar"],padx=compact_pad,pady=scaled_value(6, 5, 4)); _cxh.pack(fill=tk.X)
        tk.Label(_cxh,text="Customer",font=(label_font[0],label_font[1],"bold"),bg=C["sidebar"],fg=C["text"]).pack(side=tk.LEFT)
        tk.Label(_cxh,text="Existing or walk-in lookup",
                 font=section_meta_font,bg=C["sidebar"],fg=C["muted"]).pack(side=tk.RIGHT)
        tk.Frame(cx_outer,bg=C["teal"],height=2).pack(fill=tk.X)
        cx=tk.Frame(cx_outer,bg=C["card"],padx=compact_pad,pady=compact_inner_pad); cx.pack(fill=tk.X)

        nf = tk.Frame(cx, bg=C["card"])
        nf.pack(fill=tk.X, pady=(0, 4))
        tk.Label(nf, text="Name:", bg=C["card"],
                 fg=C["muted"], font=label_font).pack(anchor="w")
        self.name_ent = tk.Entry(nf, font=entry_font,
                                 bg=C["input"], fg=_billing_entry_fg(),
                                 bd=0, insertbackground=C["accent"])
        self.name_ent.pack(fill=tk.X, ipady=5)
        self._suggest_name_host = tk.Frame(nf, bg=C["card"])
        self._suggest_name_host.pack(fill=tk.X, pady=(2, 0))
        self._suggest_name_host.pack_forget()

        pf = tk.Frame(cx, bg=C["card"])
        pf.pack(fill=tk.X)
        tk.Label(pf, text="Phone:", bg=C["card"],
                 fg=C["muted"], font=label_font).pack(anchor="w")
        self.phone_ent = tk.Entry(pf, font=entry_font,
                                  bg=C["input"], fg=_billing_entry_fg(),
                                  bd=0, insertbackground=C["accent"])
        self.phone_ent.pack(fill=tk.X, ipady=5)
        self._suggest_phone_host = tk.Frame(pf, bg=C["card"])
        self._suggest_phone_host.pack(fill=tk.X, pady=(2, 0))
        self._suggest_phone_host.pack_forget()

        self._suggest_win   = None
        self._suggest_list  = None
        self._suggest_items = []
        self._suggest_field = None

        self.name_ent.bind("<KeyRelease>",
                           lambda e: self._on_customer_keyrelease(e, "name"))
        self.phone_ent.bind("<KeyRelease>",
                            lambda e: self._on_customer_keyrelease(e, "phone"))
        self.name_ent.bind("<FocusOut>",
                           lambda e: self.after(120, self._hide_suggestions_if_safe))
        self.phone_ent.bind("<FocusOut>",
                            lambda e: self.after(120, self._hide_suggestions_if_safe))
        self.name_ent.bind("<Escape>",
                           lambda e: self._on_customer_escape(e))
        self.phone_ent.bind("<Escape>",
                            lambda e: self._on_customer_escape(e))
        self.name_ent.bind("<Down>",
                           lambda e: self._focus_suggestion(e))
        self.phone_ent.bind("<Down>",
                            lambda e: self._focus_suggestion(e))
        self.name_ent.bind("<Up>",
                           lambda e: self._focus_suggestion(e, move=-1))
        self.phone_ent.bind("<Up>",
                            lambda e: self._focus_suggestion(e, move=-1))
        self.name_ent.bind("<Return>",
                           lambda e: self._commit_customer_suggestion(e, "name"))
        self.phone_ent.bind("<Return>",
                            lambda e: self._commit_customer_suggestion(e, "phone"))

        bd_row = tk.Frame(cx, bg=C["card"])
        bd_row.pack(fill=tk.X, pady=(6, 0))
        tk.Label(bd_row, text="Birthday (YYYY-MM-DD):",
                 bg=C["card"], fg=C["muted"],
                 font=label_font).pack(side=tk.LEFT, padx=(0, 6))
        self.bday_ent = tk.Entry(bd_row, font=entry_font,
                                   bg=C["input"], fg=_billing_entry_fg(C["gold"]),
                                   bd=0, width=14,
                                   insertbackground=C["accent"])
        self.bday_ent.pack(side=tk.LEFT, ipady=4)
        self.new_cust_lbl = tk.Label(bd_row, text="",
                                     bg=C["card"], fg=C["lime"],
                                     font=("Arial", 10, "bold"))
        self.new_cust_lbl.pack(side=tk.RIGHT)

        pts_row = tk.Frame(cx, bg=C["card"])
        pts_row.pack(fill=tk.X, pady=(4, 0))
        self.pts_lbl = tk.Label(pts_row, text="Points: -",
                                bg=C["card"], fg=C["gold"],
                                font=("Arial", 11))
        self.pts_lbl.pack(side=tk.LEFT)
        self.package_info_lbl = tk.Label(
            cx,
            text="",
            bg=C["card"],
            fg=C["gold"],
            font=("Arial", 9, "bold"),
            justify="left",
            anchor="w",
            wraplength=320,
        )
        self.package_info_lbl.pack(fill=tk.X, pady=(4, 0))
        cx.bind("<Configure>", self._on_customer_panel_resize)
        self.phone_ent.bind("<FocusOut>", self._on_phone_lookup)

        # Add Item Box
        _sb_outer=tk.Frame(lp,bg=C["card"]); _sb_outer.pack(fill=tk.X,pady=4)
        _sbh=tk.Frame(_sb_outer,bg=C["sidebar"],padx=12,pady=6); _sbh.pack(fill=tk.X)
        self._sbox_lbl=tk.Label(_sbh,text="Add Services",font=("Arial",11,"bold"),bg=C["sidebar"],fg=C["text"])
        self._sbox_lbl.pack(side=tk.LEFT)
        tk.Label(_sbh,text="Search and add with quantity",
                 font=("Arial",9),bg=C["sidebar"],fg=C["muted"]).pack(side=tk.RIGHT)
        tk.Frame(_sb_outer,bg=C["accent"],height=2).pack(fill=tk.X)
        self.s_box=tk.Frame(_sb_outer,bg=C["card"],padx=12,pady=8); self.s_box.pack(fill=tk.X)

        tk.Label(self.s_box, text="Category:", bg=C["card"],
                 fg=C["muted"], font=("Arial", 11)).pack(anchor="w")
        self.cat_v  = tk.StringVar(value="All")
        self.cat_cb = ttk.Combobox(self.s_box, textvariable=self.cat_v,
                                   state="readonly", font=("Arial", 11),
                                   style="Billing.TCombobox")
        self.cat_cb.pack(fill=tk.X, pady=(2, 4))
        self.cat_cb.bind("<<ComboboxSelected>>",
                         lambda e: self._on_cat_selected())
        self.cat_cb.bind("<MouseWheel>", lambda e: "break")

        tk.Label(self.s_box, text="Search (name / code):", bg=C["card"],
                 fg=C["muted"], font=("Arial", 11)).pack(anchor="w")
        self.search_var = tk.StringVar()

