    def _apply_redeem(self):
        code = self.redeem_ent.get().strip().upper()
        if not code:
            messagebox.showwarning("Redeem", "Enter a redeem code.")
            return
        try:
            valid, info = validate_code(code)
            if valid:
                self._applied_redeem_code = code
                val   = info.get("value", 0)
                dt    = info.get("discount_type", "flat")
                val_s = f"Rs{val:.0f}" if dt == "flat" else f"{val:.0f}%"
                self.offer_info_lbl.config(
                    text=f"Redeem '{code}' - {val_s} discount! (valid)")
                self._refresh_bill()
            else:
                messagebox.showerror("Invalid Code", info)
                self._applied_redeem_code = None
                self._refresh_bill()
        except Exception as e:
            messagebox.showerror("Redeem Error", f"Could not apply code: {e}")

    def _clear_redeem(self):
        self._applied_redeem_code = None
        self.redeem_ent.delete(0, tk.END)
        if not self._applied_offer:
            self.offer_info_lbl.config(text="")
        self._refresh_bill()

    def _calc_totals(self):
        svc  = [it for it in self.bill_items if it["mode"] == "services"]
        prd  = [it for it in self.bill_items if it["mode"] == "products"]
        s_sub = sum(i["price"] * i["qty"] for i in svc)
        p_sub = sum(i["price"] * i["qty"] for i in prd)
        total = s_sub + p_sub

        disc = 0.0
        if self.disc_enabled.get():
            disc = min(total, max(0.0, safe_float(self.disc_ent.get() or 0)))

        mem_disc = 0.0
        if getattr(self, "_membership_disc_pct", 0) > 0:
            mem_disc = round(s_sub * self._membership_disc_pct / 100, 2)
            mem_disc = max(0.0, min(mem_disc, max(0.0, total - disc)))

        pts_disc = 0.0
        if self.use_pts_var.get():
            ph = self.phone_ent.get().strip()
            c  = _billing_get_customers().get(ph)
            if c:
                remaining_for_points = max(0.0, total - disc - mem_disc)
                pts_disc = float(min(int(c.get("points", 0)),
                                     int(remaining_for_points)))
                self.pts_disc_lbl.config(text=f"Points used: Rs{pts_disc:.0f}")
            else:
                self.use_pts_var.set(False)
        else:
            self.pts_disc_lbl.config(text="")

        offer_disc = 0.0
        if self._applied_offer:
            offer_disc = apply_offer(
                self._applied_offer, self.bill_items,
                max(0.0, total - disc - pts_disc))
            offer_disc = max(0.0, offer_disc)

        redeem_disc = 0.0
        if self._applied_redeem_code:
            redeem_disc = calc_redeem_discount(
                self._applied_redeem_code,
                max(0.0, total - disc - pts_disc - offer_disc))
            redeem_disc = max(0.0, redeem_disc)

        grand = max(0.0, total - disc - mem_disc - pts_disc
                    - offer_disc - redeem_disc)
        gst   = 0.0
        if self.gst_enabled.get() and grand > 0:
            try:
                _sc   = get_settings()
                rate  = float(_sc.get("gst_rate", 18.0)) / 100
                gtype = _sc.get("gst_type", "inclusive")
                if gtype == "inclusive":
                    gst   = grand - (grand / (1 + rate))
                else:
                    gst   = grand * rate
                    grand = grand + gst
            except Exception:
                gst = grand - (grand / 1.18)

        return (s_sub, p_sub, total, disc, mem_disc, pts_disc,
                offer_disc, redeem_disc, grand, gst)

    def _refresh_bill(self):
        """Generate bill preview using print_engine."""
        try:
            self._refresh_bill_inner()
        except Exception as e:
            app_log(f"[_refresh_bill] {e}")

    def _refresh_bill_inner(self):
        """Inner bill preview ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â called by _refresh_bill with error guard."""
        from print_engine import generate_thermal_text, BillData, get_print_settings

        cfg = get_settings()
        (svc_s, prd_s, total, disc, mem_disc, pts_disc,
         offer_disc, redeem_disc, grand, gst) = self._calc_totals()

        svc_items = [it for it in self.bill_items if it["mode"] == "services"]
        prd_items = [it for it in self.bill_items if it["mode"] == "products"]

        now    = datetime.now()
        ps     = get_print_settings()
        W      = int(safe_float(cfg.get("print_width_chars",
                                         cfg.get("bill_width", 32)), 32))
        ps["printer_width"] = W  # use settings-configured width

        gst_type = cfg.get("gst_type", "inclusive")
        gst_rate = float(cfg.get("gst_rate", 18.0))

        offer_name = (self._applied_offer.get("name", "Offer")
                      if self._applied_offer else "")

        invoice_branding = get_invoice_branding()
        bill = BillData(
            invoice        = self._current_invoice,
            salon_name     = cfg.get("salon_name") or invoice_branding["header"],
            address        = cfg.get("address") or invoice_branding["address"],
            phone          = cfg.get("phone") or invoice_branding["phone"],
            gst_no         = cfg.get("gst_no", ""),
            customer_name  = self.name_ent.get(),
            customer_phone = self.phone_ent.get(),
            payment_method = self.payment_var.get(),
            svc_items      = svc_items,
            prd_items      = prd_items,
            subtotal       = total,
            discount       = disc,
            mem_discount   = mem_disc,
            mem_pct        = int(getattr(self, "_membership_disc_pct", 0)),
            pts_discount   = pts_disc,
            offer_discount = offer_disc,
            offer_name     = offer_name,
            redeem_discount= redeem_disc,
            redeem_code    = self._applied_redeem_code or "",
            gst_amount     = gst,
            gst_rate       = gst_rate,
            gst_type       = gst_type,
            grand_total    = grand,
            timestamp      = now.strftime("%Y-%m-%d %H:%M"),
        )

        text = generate_thermal_text(bill, ps)
        self.txt.delete("1.0", tk.END)
        self.txt.insert(tk.END, text)
        self.total_lbl.config(text=f"Total: Rs{grand:.2f}")

