    def prefill_from_booking(self, booking):
        booking = dict(booking or {})
        has_existing = bool(self.bill_items or self.name_ent.get().strip() or self.phone_ent.get().strip())
        if has_existing:
            if not messagebox.askyesno(
                "Convert Booking to Bill",
                "This will start a new bill and clear the current billing draft. Continue?",
            ):
                return
        self.clear_all()
        self.name_ent.insert(0, str(booking.get("customer_name", "")).strip())
        self.phone_ent.insert(0, str(booking.get("phone", "")).strip())
        service_name = str(booking.get("service", "")).strip()
        if service_name:
            try:
                self.set_mode("services")
            except Exception:
                pass
            exact = self._get_exact_match(service_name)
            if exact:
                self._apply_search_selection(exact)
                self.add_item()
            else:
                self.search_var.set(service_name)
        try:
            self._refresh_bill()
        except Exception:
            pass

    def _right_click_menu(self, e=None):
        """
        Bug 4 fix: removed finally: grab_release() which prevented
        menu items from being clicked on Windows.
        """
        if not self.bill_items: return
        try:
            self._register_billing_context_menu_callbacks()
            from shared.context_menu.constants import WidgetType
            from shared.context_menu.menu_context_factory import build_context
            from shared.context_menu.renderer import renderer_service
            from shared.context_menu_definitions.billing_context_menu import get_sections

            total_amount = 0.0
            try:
                total_amount = float(self._calc_totals()[8])
            except Exception:
                total_amount = 0.0
            context = build_context(
                "billing",
                entity_type="current_bill",
                entity_id=self._current_invoice,
                widget_type=WidgetType.TEXT,
                widget_id="billing_preview",
                screen_x=getattr(e, "x_root", None),
                screen_y=getattr(e, "y_root", None),
                user_role=self.app.current_user.get("role", "") if getattr(self.app, "current_user", None) else "",
                extra={
                    "has_bill_items": bool(self.bill_items),
                    "invoice_number": self._current_invoice,
                    "total_amount": total_amount,
                },
            )
            menu = renderer_service.build_menu(self, get_sections(), context)
            menu.tk_popup(e.x_root, e.y_root)   # Bug 4 fix: no grab_release here
        except Exception as exc:
            app_log(f"[billing context menu] {exc}")

    def _register_billing_context_menu_callbacks(self):
        from shared.context_menu.action_adapter import action_adapter
        from shared.context_menu.clipboard_service import clipboard_service
        from shared.context_menu_definitions.billing_context_menu import BillingContextAction

        action_adapter.register(BillingContextAction.EDIT_ITEMS, lambda _ctx, _act: self._edit_item_qty())
        action_adapter.register(BillingContextAction.UNDO_LAST, lambda _ctx, _act: self.undo_last())
        action_adapter.register(BillingContextAction.SAVE, lambda _ctx, _act: self.manual_save())
        action_adapter.register(BillingContextAction.PRINT, lambda _ctx, _act: self.print_bill())
        action_adapter.register(BillingContextAction.EXPORT_PDF, lambda _ctx, _act: self.save_pdf())
        action_adapter.register(BillingContextAction.WHATSAPP, lambda _ctx, _act: self.send_whatsapp())
        action_adapter.register(BillingContextAction.CLEAR, lambda _ctx, _act: self.clear_all())
        action_adapter.register(
            BillingContextAction.COPY_INVOICE,
            lambda ctx, _act: clipboard_service.copy_text(self, ctx.extra.get("invoice_number", "")),
        )
        action_adapter.register(
            BillingContextAction.COPY_TOTAL,
            lambda ctx, _act: clipboard_service.copy_text(self, f"{float(ctx.extra.get('total_amount', 0.0)):.2f}"),
        )

    def _bind_shortcuts(self):
        """Keyboard shortcuts for fast billing."""
        root = self.winfo_toplevel()
